for (const [name, path] of Object.entries(icons)) {
  const tag = `mdui-icon-${name}`;
  if (!customElements.get(tag)) {
    customElements.define(tag, class extends HTMLElement {
      connectedCallback() {
        this.classList.add("mdui-svg-icon");
        if (!this.hasAttribute("aria-hidden") && !this.hasAttribute("aria-label")) {
          this.setAttribute("aria-hidden", "true");
        }
        this.innerHTML = `<svg viewBox="0 0 24 24" aria-hidden="true" part="svg" fill="currentColor">${path}</svg>`;
      }
    });
  }
}
